package main

import (
    "fmt"
    "os"
)

// Noncompliant: Predictable file name
func createTempFileBad() error {
    fileName := "/tmp/myapp_temp.txt"
    file, err := os.Create(fileName)
    if err != nil {
        return err
    }
    defer file.Close()
    // Predictable name allows attacks
    return nil
}

// Noncompliant: Using process ID (still predictable)
func createTempFilePredictable() error {
    fileName := fmt.Sprintf("/tmp/myapp_%d.txt", os.Getpid())
    file, err := os.Create(fileName)
    if err != nil {
        return err
    }
    defer file.Close()
    return nil
}

// Noncompliant: Insecure permissions
func createTempFileInsecure() error {
    file, err := os.OpenFile("/tmp/temp.txt", os.O_CREATE|os.O_WRONLY, 0777) // Too permissive
    if err != nil {
        return err
    }
    defer file.Close()
    return nil
}

