package main

import (
    "io/ioutil"
    "os"
)

// Compliant: Use ioutil.TempFile for secure creation
func createTempFileSecure() (*os.File, error) {
    // Creates file with random name and secure permissions (0600)
    tempFile, err := ioutil.TempFile("", "myapp_*.txt")
    if err != nil {
        return nil, err
    }
    return tempFile, nil
}

// Compliant: Use os.CreateTemp (Go 1.16+)
func createTempFileModern() (*os.File, error) {
    tempFile, err := os.CreateTemp("", "myapp_*.txt")
    if err != nil {
        return nil, err
    }
    return tempFile, nil
}

// Compliant: Secure temporary directory
func createTempDirSecure() (string, error) {
    tempDir, err := ioutil.TempDir("", "myapp_*")
    if err != nil {
        return "", err
    }
    return tempDir, nil
}

// Compliant: Proper cleanup
func useTemporaryFile() error {
    tempFile, err := os.CreateTemp("", "myapp_*.txt")
    if err != nil {
        return err
    }
    defer func() {
        tempFile.Close()
        os.Remove(tempFile.Name()) // Clean up
    }()

    // Use the temporary file
    _, err = tempFile.WriteString("temporary data")
    return err
}
